const items = $input.all().map(i => i.json);
  if (!items.length || !items[0].user_id) return [];
  return items.map(item => ({ json: item }));

const response = $input.first().json;
const context = $('Loop Sources').first().json;
const sourceUrl = context.source_url;
const rootDomain = sourceUrl.match(/^https?:\/\/[^\/]+/)?.[0] || sourceUrl;
const basePath = sourceUrl.replace(/\/+$/, '');

// Extract body — avoid JSON.stringify fallback (can cause false Cloudflare matches from response metadata)
let body = '';
if (typeof response === 'string') {
  body = response;
} else if (response.data) {
  body = String(response.data);
} else if (response.body) {
  body = String(response.body);
}

// If page fetch failed, try feed at source path (handles WordPress in subdirs like gsqi.com/marketing-blog/)
if (!body || body.length < 100 || /cf-error|cloudflare/i.test(body) || response.error) {
  return [{ json: { ...context, feedUrl: basePath + '/feed/' } }];
}

// Already RSS/Atom? Re-use source URL
if (/<rss|<feed[\s>]|<item>|<entry>/i.test(body)) {
  return [{ json: { ...context, feedUrl: sourceUrl } }];
}

// RSS autodiscovery in HTML <link> tags
const rssLink = body.match(/<link[^>]*type=["']application\/rss\+xml["'][^>]*href=["']([^"']+)["']/i)
  || body.match(/<link[^>]*href=["']([^"']+)["'][^>]*type=["']application\/rss\+xml["']/i)
  || body.match(/<link[^>]*type=["']application\/atom\+xml["'][^>]*href=["']([^"']+)["']/i);

if (rssLink && rssLink[1]) {
  let feedUrl = rssLink[1];
  if (feedUrl.startsWith('/')) {
    feedUrl = rootDomain + feedUrl;
  }
  return [{ json: { ...context, feedUrl } }];
}

// Fallback: /feed at the source URL path (not root domain — handles subdirectory blogs)
return [{ json: { ...context, feedUrl: basePath + '/feed/' } }];

const response = $input.first().json;
const context = $('Get Feed URL').first().json;

// Extract body
let body = '';
if (typeof response === 'string') { body = response; }
else if (response.data) { body = String(response.data); }
else if (response.body) { body = String(response.body); }

if (!body || body.length < 50) return [];

const articles = [];
let match;

// RSS 2.0
const rssRegex = /<item>([\s\S]*?)<\/item>/gi;
while ((match = rssRegex.exec(body)) !== null) {
  const xml = match[1];
  const title = (xml.match(/<title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
  const link = (xml.match(/<link>([\s\S]*?)<\/link>/) || [])[1] || '';
  const desc = (xml.match(/<description>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/) || [])[1] || '';
  const content = (xml.match(/<content:encoded>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/content:encoded>/) || [])[1] || '';
  if (link.trim()) {
    articles.push({
      article_title: title.trim().replace(/<[^>]*>/g, ''),
      article_url: link.trim(),
      article_text: (content || desc).replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 3000),
      article_hash: link.trim()
    });
  }
}

// Atom
if (articles.length === 0) {
  const atomRegex = /<entry>([\s\S]*?)<\/entry>/gi;
  while ((match = atomRegex.exec(body)) !== null) {
    const xml = match[1];
    const title = (xml.match(/<title[^>]*>([\s\S]*?)<\/title>/) || [])[1] || '';
    const link = (xml.match(/<link[^>]*href=["']([^"']*)["']/) || [])[1] || '';
    const content = (xml.match(/<(?:content|summary)[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/(?:content|summary)>/) || [])[1] || '';
    if (link.trim()) {
      articles.push({
        article_title: title.trim().replace(/<[^>]*>/g, ''),
        article_url: link.trim(),
        article_text: content.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 3000),
        article_hash: link.trim()
      });
    }
  }
}

// Google News Sitemap
if (articles.length === 0) {
  const urlRegex = /<url>([\s\S]*?)<\/url>/gi;
  while ((match = urlRegex.exec(body)) !== null) {
    const xml = match[1];
    const loc = (xml.match(/<loc>([^<]*)<\/loc>/) || [])[1] || '';
    const title = (xml.match(/<news:title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/news:title>/) || [])[1]
      || (xml.match(/<title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
    if (loc.trim() && title.trim()) {
      articles.push({
        article_title: title.trim().replace(/<[^>]*>/g, ''),
        article_url: loc.trim(),
        article_text: title.trim(),
        article_hash: loc.trim()
      });
    }
  }
}

if (articles.length === 0) return [];
const recent = articles.slice(0, 10);

return recent.map(a => ({ json: {
  ...a,
  user_id: context.user_id,
  source_id: context.source_id,
  source_name: context.source_name,
  source_url: context.source_url,
  priorities: context.priorities
}}));

const dedupeResult = $input.first().json;
const article = $('Loop Articles').first().json;

// If dedupe returned an id, the article already exists
const isNew = !dedupeResult.id;

return [{ json: { ...article, isNew } }];

const a = $input.first().json;
return [{ json: {
  ...a,
  query: 'Source: ' + a.source_name + '\nTitle: ' + a.article_title + '\nURL: ' + a.article_url + '\n\n' + a.article_text
}}];

let raw = $input.first().json.output;
const article = $('Build Radar Context').first().json;

let parsed;
if (typeof raw === 'object' && raw !== null) {
  parsed = raw;
} else {
  let text = String(raw || '').trim();
  text = text.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?\s*```\s*$/, '').trim();
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    const match = text.match(/\{[\s\S]*"decision"[\s\S]*\}$/);
    if (match) {
      try { parsed = JSON.parse(match[0]); } catch (e2) { parsed = null; }
    }
    if (!parsed) {
      parsed = { decision: 'drop', reason: 'Could not parse agent output' };
    }
  }
}

return [{ json: { ...article, decision: parsed.decision, matched_priority: parsed.matched_priority || '', rationale: parsed.rationale || parsed.reason || '' } }];

